Here's a step-by-step guide to create a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

1. Create a new C++ file, e.g., `word_count.cpp`.

2. Include necessary libraries:

```cpp
#include <iostream>
#include <fstream>
#include <string>
```

3. Implement a function to count the occurrences of the given word in a single line:

```cpp
int count_word_in_line(const std::string &line, const std::string &target) {
    int count = 0;
    size_t start_pos = 0;

    while ((start_pos = line.find(target, start_pos)) != std::string::npos) {
        ++count;
        start_pos += target.length();
    }

    return count;
}
```

4. Implement the main function to open the input file, read it line by line, and output the result:

```cpp
int main(int argc, char *argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <filename> <target_word>" << std::endl;
        return 1;
    }

    std::ifstream input_file(argv[1]);
    if (!input_file.is_open()) {
        std::cerr << "Error opening file: " << argv[1] << std::endl;
        return 1;
    }

    std::string target_word = argv[2];
    int total_count = 0;

    std::string line;
    while (std::getline(input_file, line)) {
        total_count += count_word_in_line(line, target_word);
    }

    input_file.close();

    std::cout << "The word '" << target_word << "' occurs " << total_count << " times in the file." << std::endl;

    return 0;
}
```

